    public class JwtAuthenticationMiddleware : IMiddleware
    {
        private readonly ILogger<JwtAuthenticationMiddleware> _logger;

        public JwtAuthenticationMiddleware(ILogger<JwtAuthenticationMiddleware> logger)
        {
            _logger = logger;
        }

        public Task InvokeAsync(HttpContext httpContext, Func<Task> next)
        {
            // Extract the JWT from the Authorization header
            var tokenString = httpContext.Request.Headers["Authorization"].FirstOrDefault();

            if (tokenString is null)
            {
                _logger.LogWarning("No JWT found in request");
                return next();
            }

            // Verify the signature of the JWT
            var token = new JwtSecurityToken(tokenString);
            var key = GetJwtKey();
            if (!token.VerifySignature(key))
            {
                _logger.LogWarning("JWT signature verification failed");
                return next();
            }

            // Populate the HttpContext user with the JWT claims
            var identity = new ClaimsIdentity(token.Claims, "Jwt");
            httpContext.User = new ClaimsPrincipal(identity);

            _logger.LogInformation("JWT authentication successful");
            return next();
        }

        private string GetJwtKey()
        {
            // TODO: Implement a way to retrieve the JWT key from your configuration or storage
            return "your_jwt_key";
        }
    }
